// Types matching the Python Redux store

export type PanelId = 
  | 'task' 
  | 'perm' 
  | 'tool' 
  | 'improve' 
  | 'route' 
  | 'verify' 
  | 'msg' 
  | 'ctrl' 
  | 'config';

// Console modes matching Python ConsoleMode
export const CONSOLE_MODES = {
  TASK: '[task]',
  PERM: '[perm]',
  TOOL: '[tool]',
  IMPROVE: '[improve]',
  ROUTE: '[route]',
  VERIFY: '[verify]',
  MSG: '[msg]',
  CTRL: '[ctrl]',
  CONFIG: '[config]',
  GLOBAL: '>',
} as const;

export type ConsoleMode = typeof CONSOLE_MODES[keyof typeof CONSOLE_MODES];

// Status types
export type AgentStatus = 'idle' | 'planning' | 'executing' | 'waiting' | 'paused' | 'completed' | 'failed' | 'terminated';
export type TaskStatus = 'pending' | 'in_progress' | 'completed' | 'failed' | 'cancelled';
export type TaskPriority = 'low' | 'normal' | 'high' | 'critical';
export type PermissionAction = 'approve' | 'deny' | 'ask';
export type MessagePriority = 'low' | 'normal' | 'high' | 'critical';
export type VerificationStatus = 'PENDING' | 'IN_PROGRESS' | 'VERIFIED' | 'FAILED';

// Backend Metrics from Python BackendMetrics dataclass
export interface BackendMetrics {
  total_calls: number;
  success_count: number;
  failure_count: number;
  total_latency: number;
  avg_latency: number;
  last_used: number;
}

// Task entity
export interface TaskEntity {
  task_id: string;
  description: string;
  status: TaskStatus;
  priority: TaskPriority;
  created_at: number;
  started_at: number | null;
  completed_at: number | null;
  result: unknown | null;
  error: string | null;
}

// Permission request
export interface PermissionRequest {
  request_id: string;
  permission_type: string;
  agent_id: string;
  description: string;
  risk_assessment: string;
  created_at: number;
}

// Tool definition
export interface ToolDefinition {
  tool_id: string;
  name: string;
  description: string;
  code: string;
  created_by: string;
  created_at: number;
  status: 'pending' | 'approved' | 'rejected';
}

// Improvement entity
export interface ImprovementEntity {
  improvement_id: string;
  title: string;
  description: string;
  category: string;
  impact: 'low' | 'medium' | 'high';
  status: 'proposed' | 'reviewing' | 'approved' | 'rejected' | 'applied';
  created_by: string;
  created_at: number;
}

// Agent entity
export interface AgentEntity {
  agent_id: string;
  name: string;
  status: AgentStatus;
  parent_id: string | null;
  task: string;
  created_at: number;
  last_update: number;
}

// Message entity
export interface MessageEntity {
  message_id: string;
  sender: string;
  recipients: string[];
  content: string;
  timestamp: number;
  priority: MessagePriority;
  read: boolean;
}

// Layer1 status
export interface Layer1Status {
  status: 'loading' | 'loaded' | 'error';
  mathlib_version: string | null;
  physlib_version: string | null;
}

// Theorem record
export interface TheoremRecord {
  theorem_id: string;
  theorem_text: string;
  status: VerificationStatus;
  proof_attempts: number;
  created_at: number;
  completed_at: number | null;
}

// Intervention record
export interface InterventionRecord {
  id: string;
  action_type: 'pause' | 'resume' | 'terminate' | 'emergency_stop';
  target_type: 'agent' | 'group' | 'type' | 'all';
  target_id: string | null;
  timestamp: number;
  reason: string | null;
}

// Routing decision
export interface RoutingDecision {
  decision_id: string;
  decision_type: 'backend' | 'environment';
  selected: string;
  alternatives: string[];
  timestamp: number;
}

// System configuration
export interface SystemConfiguration {
  resourceLimits: {
    cpu: number;
    memory: number;
    tokens: number;
  };
  security: {
    messageValidation: boolean;
    toolApprovalRequired: boolean;
    agentIsolation: boolean;
  };
  performance: {
    messageBatchSize: number;
    stateUpdateInterval: number;
    cleanupInterval: number;
  };
  realtime: {
    mode: 'websocket' | 'polling';
    pollInterval: number;
  };
  retention: {
    maxThreads: number;
    autoArchiveAfter: number;
    persistAll: boolean;
  };
}

// UI state
export interface UIState {
  activePanel: PanelId;
  commandBarOpen: boolean;
  commandInput: string;
  notifications: Notification[];
  splitView: boolean;
  searchQuery: string;
}

// Notification
export interface Notification {
  id: string;
  type: 'info' | 'success' | 'warning' | 'error';
  title: string;
  message: string;
  timestamp: number;
  read: boolean;
}

// WebSocket message types
export interface WSMessage {
  type: 'subscribe' | 'unsubscribe' | 'dispatch' | 'pong' | 'state_update' | 'dispatch_ack' | 'ping';
  payload: Record<string, unknown>;
}

// Root state (mirrors Python RootState)
export interface RootState {
  agents: {
    agents: Record<string, AgentEntity>;
    paused_agents: string[];
    all_paused: boolean;
    timeline: InterventionRecord[];
  };
  tasks: {
    tasks: Record<string, TaskEntity>;
    task_queue: string[];
    completed_tasks: string[];
    failed_tasks: string[];
  };
  permissions: {
    pending_requests: PermissionRequest[];
    defaults: Record<string, PermissionAction>;
    history: Array<{ request_id: string; action: PermissionAction; timestamp: number }>;
  };
  tools: {
    pending_tools: ToolDefinition[];
    approved_tools: string[];
    rejected_tools: string[];
    defaults: Record<string, 'approve' | 'reject' | 'ask'>;
  };
  improvements: {
    pending_approvals: ImprovementEntity[];
    active_improvements: string[];
    defaults: Record<string, 'approve' | 'reject' | 'ask'>;
  };
  routing: {
    current_route: {
      backend: string | null;
      environment: string | null;
      mode: 'local' | 'modal' | null;
      data_sensitivity: 'public' | 'internal' | 'restricted' | null;
    };
    backend_metrics: Record<string, BackendMetrics>;
    decisions: Record<string, RoutingDecision>;
    defaults: {
      global: string | null;
      by_agent: Record<string, string>;
      by_type: Record<string, string>;
    };
  };
  verification: {
    status: VerificationStatus;
    active_verification: string | null;
    verification_queue: string[];
    layer1: Layer1Status;
    resource_usage: {
      cpu_percent: number;
      memory_mb: number;
    };
    theorems: Record<string, TheoremRecord>;
  };
  messages: {
    threads: Record<string, MessageEntity[]>;
    inbox: Record<string, MessageEntity[]>;
    unread_counts: Record<string, number>;
    retention: {
      max_threads: number;
      auto_archive_after: number;
      persist_all: boolean;
    };
  };
  system: {
    status: 'idle' | 'running' | 'paused' | 'error';
    config: SystemConfiguration;
    session_id: string | null;
  };
  ui: UIState;
}
